insert into auth.identities (
  id, user_id, provider_id, identity_data, provider,
  last_sign_in_at, created_at, updated_at
)
select
  u.id,
  u.id,
  u.id::text,
  jsonb_build_object(
    'sub',            u.id::text,
    'email',          u.email,
    'email_verified', true,
    'provider',       'email'
  ),
  'email',
  now(), now(), now()
from auth.users u
where not exists (
  select 1 from auth.identities i where i.user_id = u.id
);

update auth.identities
set
  id = user_id,
  provider_id = user_id::text,
  identity_data = identity_data
    || jsonb_build_object('sub', user_id::text, 'provider', provider)
    || case
         when provider = 'email' and email is not null
           then jsonb_build_object('email', email, 'email_verified', true)
         else '{}'::jsonb
       end,
  updated_at = now()
where provider = 'email'
  and (
    id <> user_id
    or provider_id <> user_id::text
    or coalesce(identity_data->>'sub', '') <> user_id::text
  );

update auth.users
set
  raw_app_meta_data = coalesce(raw_app_meta_data, '{"provider":"email","providers":["email"]}'::jsonb),
  raw_user_meta_data = coalesce(raw_user_meta_data, '{}'::jsonb),
  email_confirmed_at = coalesce(email_confirmed_at, now()),
  confirmation_token = coalesce(confirmation_token, ''),
  recovery_token = coalesce(recovery_token, ''),
  email_change_token_new = coalesce(email_change_token_new, ''),
  email_change = coalesce(email_change, ''),
  email_change_token_current = coalesce(email_change_token_current, ''),
  reauthentication_token = coalesce(reauthentication_token, ''),
  updated_at = now()
where email like '%@sescoin.local';


