-- ============================================================
-- EXTENSIONS
-- ============================================================

create extension if not exists "uuid-ossp";
create extension if not exists "pgcrypto";


-- ============================================================
-- TABLE : profiles
-- ============================================================

create table public.profiles (
  id uuid primary key references auth.users(id) on delete cascade,
  username text not null unique,
  display_name text not null,
  balance numeric(12, 2) not null default 0,
  role text not null default 'student'
    check (role in ('student', 'admin')),
  is_banned boolean not null default false,
  ban_reason text,
  avatar_url text,
  pending_avatar_url text,
  fcm_token text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index idx_profiles_username on public.profiles(username);
create index idx_profiles_balance on public.profiles(balance desc);
create index idx_profiles_role on public.profiles(role);


-- ============================================================
-- TABLE : account_requests
-- ============================================================

create table public.account_requests (
  id uuid primary key default uuid_generate_v4(),
  first_name text not null,
  last_name text not null,
  username text not null unique,
  password_hash text not null,
  avatar_url text,
  device_id text,
  status text not null default 'pending'
    check (status in ('pending', 'approved', 'refused')),
  initial_balance numeric(12, 2),
  refusal_reason text,
  rejection_reason text,
  reviewed_at timestamptz,
  reviewed_by uuid references public.profiles(id) on delete set null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index idx_account_requests_username on public.account_requests(username);
create index idx_account_requests_status on public.account_requests(status);
create index idx_account_requests_device on public.account_requests(device_id);


-- ============================================================
-- TABLE : transactions
-- ============================================================

create table public.transactions (
  id uuid primary key default uuid_generate_v4(),
  from_user_id uuid not null references public.profiles(id) on delete cascade,
  to_user_id uuid not null references public.profiles(id) on delete cascade,
  amount numeric(12, 2) not null check (amount > 0),
  type text not null check (
    type in (
      'transfer', 'purchase', 'auction', 'loan',
      'reward', 'tax', 'admin_credit', 'admin_debit', 'initial_balance'
    )
  ),
  description text,
  metadata jsonb,
  created_at timestamptz not null default now()
);

create index idx_transactions_from on public.transactions(from_user_id);
create index idx_transactions_to on public.transactions(to_user_id);
create index idx_transactions_created_at on public.transactions(created_at desc);


-- ============================================================
-- TABLE : marketplace_items
-- ============================================================

create table public.marketplace_items (
  id uuid primary key default uuid_generate_v4(),
  name text not null,
  description text not null default '',
  price numeric(12, 2) not null check (price > 0),
  image_url text,
  category text not null default 'Divers',
  stock integer not null default -1,
  is_active boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index idx_marketplace_items_category on public.marketplace_items(category);
create index idx_marketplace_items_active on public.marketplace_items(is_active);


-- ============================================================
-- TABLE : purchases
-- ============================================================

create table public.purchases (
  id uuid primary key default uuid_generate_v4(),
  buyer_id uuid not null references public.profiles(id) on delete cascade,
  item_id uuid not null references public.marketplace_items(id) on delete cascade,
  quantity integer not null default 1 check (quantity > 0),
  total_price numeric(12, 2) not null,
  transaction_id uuid references public.transactions(id) on delete set null,
  created_at timestamptz not null default now()
);

create index idx_purchases_buyer on public.purchases(buyer_id);
create index idx_purchases_item on public.purchases(item_id);


-- ============================================================
-- TABLE : auctions
-- ============================================================

create table public.auctions (
  id uuid primary key default uuid_generate_v4(),
  item_name text not null,
  item_description text not null default '',
  item_image_url text,
  starting_price numeric(12, 2) not null check (starting_price >= 0),
  current_price numeric(12, 2) not null check (current_price >= 0),
  current_winner_id uuid references public.profiles(id) on delete set null,
  current_winner_username text,
  current_winner_emoji text,
  status text not null default 'active'
    check (status in ('upcoming', 'active', 'ended', 'cancelled')),
  starts_at timestamptz not null default now(),
  ends_at timestamptz not null,
  bid_count integer not null default 0,
  created_at timestamptz not null default now()
);

create index idx_auctions_status on public.auctions(status);
create index idx_auctions_ends_at on public.auctions(ends_at);


-- ============================================================
-- TABLE : auction_bids
-- ============================================================

create table public.auction_bids (
  id uuid primary key default uuid_generate_v4(),
  auction_id uuid not null references public.auctions(id) on delete cascade,
  bidder_id uuid not null references public.profiles(id) on delete cascade,
  bidder_username text not null,
  amount numeric(12, 2) not null check (amount > 0),
  created_at timestamptz not null default now()
);

create index idx_auction_bids_auction on public.auction_bids(auction_id);
create index idx_auction_bids_bidder on public.auction_bids(bidder_id);


-- ============================================================
-- TABLE : loans
-- ============================================================

create table public.loans (
  id uuid primary key default uuid_generate_v4(),
  lender_id uuid not null references public.profiles(id) on delete cascade,
  lender_username text not null,
  borrower_id uuid not null references public.profiles(id) on delete cascade,
  borrower_username text not null,
  principal numeric(12, 2) not null check (principal > 0),
  interest_rate numeric(6, 2) not null default 0 check (interest_rate >= 0),
  total_due numeric(12, 2) not null check (total_due > 0),
  amount_repaid numeric(12, 2) not null default 0 check (amount_repaid >= 0),
  status text not null default 'pending'
    check (status in ('pending', 'active', 'repaid', 'defaulted', 'rejected', 'cancelled')),
  due_date timestamptz,
  note text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index idx_loans_lender on public.loans(lender_id);
create index idx_loans_borrower on public.loans(borrower_id);
create index idx_loans_status on public.loans(status);


-- ============================================================
-- TABLE : exchange_rates
-- ============================================================

create table public.exchange_rates (
  id uuid primary key default uuid_generate_v4(),
  rate numeric(10, 4) not null check (rate > 0),
  change_percent numeric(8, 4) not null default 0,
  reason text,
  is_manual boolean not null default false,
  demand_points jsonb not null default '[0,189,180,147,705,0,0,0,0,0]'::jsonb,
  supply_points jsonb not null default '[0,161,29,138,139,0,0,0,0,0]'::jsonb,
  price_points jsonb not null default '[1.0,1.1,7.2,7.7,39.3,39.3,39.3,39.3,39.3,39.3]'::jsonb,
  created_at timestamptz not null default now()
);

create index idx_exchange_rates_created_at on public.exchange_rates(created_at desc);

insert into public.exchange_rates (
  rate, change_percent, reason, is_manual,
  demand_points, supply_points, price_points
)
values (
  1.0000, 0, 'Taux initial', false,
  '[0,189,180,147,705,0,0,0,0,0]'::jsonb,
  '[0,161,29,138,139,0,0,0,0,0]'::jsonb,
  '[1.0,1.1,7.2,7.7,39.3,39.3,39.3,39.3,39.3,39.3]'::jsonb
);


-- ============================================================
-- TABLE : notifications
-- ============================================================

create table public.notifications (
  id uuid primary key default uuid_generate_v4(),
  user_id uuid not null references public.profiles(id) on delete cascade,
  type text not null check (
    type in (
      'transaction_received', 'transaction_sent', 'transaction_confirmation_required',
      'auction_outbid', 'auction_won', 'auction_ended',
      'loan_requested', 'loan_accepted', 'loan_rejected', 'loan_repaid', 'loan_overdue',
      'marketplace_purchase', 'account_approved', 'account_rejected',
      'admin_tax', 'admin_reward', 'system'
    )
  ),
  title text not null,
  body text not null,
  data jsonb,
  is_read boolean not null default false,
  created_at timestamptz not null default now()
);

create index idx_notifications_user on public.notifications(user_id);
create index idx_notifications_read on public.notifications(is_read);
create index idx_notifications_created on public.notifications(created_at desc);


-- ============================================================
-- TABLE : payment_requests
-- ============================================================

create table public.payment_requests (
  token uuid primary key default uuid_generate_v4(),
  recipient_id uuid not null references public.profiles(id) on delete cascade,
  payer_id uuid references public.profiles(id) on delete set null,
  amount numeric(12, 2) not null check (amount > 0),
  description text,
  payment_method text check (payment_method in ('qr', 'nfc')),
  status text not null default 'pending'
    check (status in ('pending', 'confirmed', 'acknowledged', 'cancelled', 'expired')),
  transaction_id uuid references public.transactions(id) on delete set null,
  created_at timestamptz not null default now(),
  expires_at timestamptz not null default (now() + interval '10 minutes')
);

create index idx_payment_requests_recipient on public.payment_requests(recipient_id);
create index idx_payment_requests_status on public.payment_requests(status);


-- ============================================================
-- TRIGGERS updated_at
-- ============================================================

create or replace function public.update_updated_at()
returns trigger language plpgsql as $$
begin
  new.updated_at = now();
  return new;
end;
$$;

create trigger trg_profiles_updated_at
before update on public.profiles
for each row execute function public.update_updated_at();

create trigger trg_account_requests_updated_at
before update on public.account_requests
for each row execute function public.update_updated_at();

create trigger trg_marketplace_items_updated_at
before update on public.marketplace_items
for each row execute function public.update_updated_at();

create trigger trg_loans_updated_at
before update on public.loans
for each row execute function public.update_updated_at();


-- ============================================================
-- Normalisation status account_requests
-- ============================================================

create or replace function public.normalize_account_request_status()
returns trigger language plpgsql as $$
begin
  if new.status = 'rejected' then
    new.status := 'refused';
  end if;
  if new.rejection_reason is not null and new.refusal_reason is null then
    new.refusal_reason := new.rejection_reason;
  end if;
  return new;
end;
$$;

create trigger trg_normalize_account_request_status
before insert or update on public.account_requests
for each row execute function public.normalize_account_request_status();


