-- ============================================================

create or replace function public.is_username_available(p_username text)
returns boolean
language sql security definer set search_path = public, auth
as $$
  select
    not exists (select 1 from public.profiles where username = p_username)
    and
    not exists (
      select 1 from public.account_requests
      where username = p_username and status in ('pending', 'approved')
    )
    and
    not exists (
      select 1 from auth.users
      where email = p_username || '@sescoin.local'
    );
$$;

grant execute on function public.is_username_available to anon, authenticated;


-- ============================================================
-- RPC : submit_account_request
-- ============================================================

create or replace function public.submit_account_request(
  p_first_name text,
  p_last_name text,
  p_username text,
  p_password text,
  p_avatar_url text,
  p_device_id text
)
returns jsonb
language plpgsql security definer set search_path = public, auth, extensions
as $$
declare
  v_request public.account_requests%rowtype;
  v_count integer;
begin
  if p_password is null or length(p_password) < 8 then
    raise exception 'Le mot de passe doit contenir au moins 8 caracteres.';
  end if;

  if p_username !~ '^[a-z]+\.[a-z]+$' then
    raise exception 'Identifiant invalide.';
  end if;

  if exists (select 1 from public.profiles where username = p_username) then
    raise exception 'Cet identifiant est deja utilise.';
  end if;

  if exists (select 1 from auth.users where email = p_username || '@sescoin.local') then
    raise exception 'Cet identifiant est deja utilise.';
  end if;

  if exists (
    select 1 from public.account_requests
    where username = p_username and status in ('pending', 'approved')
  ) then
    raise exception 'Une demande est deja en attente pour cet identifiant.';
  end if;

  select count(*) into v_count
  from public.account_requests
  where device_id = p_device_id;

  if v_count >= 3 then
    raise exception 'Nombre maximum de demandes atteint pour cet appareil.';
  end if;

  insert into public.account_requests (
    first_name, last_name, username,
    password_hash, avatar_url, device_id, status
  )
  values (
    p_first_name, p_last_name, p_username,
    crypt(p_password, gen_salt('bf')),
    p_avatar_url, p_device_id, 'pending'
  )
  returning * into v_request;

  return to_jsonb(v_request);
end;
$$;


