create or replace function public.approve_account_request(
  p_request_id uuid,
  p_initial_balance numeric
)
returns void
language plpgsql security definer set search_path = public, auth, extensions
as $$
declare
  v_request public.account_requests%rowtype;
  v_user_id uuid;
  v_email text;
  v_admin_id uuid;
begin
  if not public.current_profile_is_admin() then
    raise exception 'Action reservee a l''administrateur.';
  end if;

  v_admin_id := auth.uid();

  select * into v_request
  from public.account_requests
  where id = p_request_id and status = 'pending'
  for update;

  if not found then
    raise exception 'Demande introuvable ou deja traitee.';
  end if;

