    insert into auth.identities (
      id, user_id, provider_id, identity_data, provider,
      last_sign_in_at, created_at, updated_at
    )
    select
      v_user_id, v_user_id, v_user_id::text,
      jsonb_build_object(
        'sub',            v_user_id::text,
        'email',          v_email,
        'email_verified', true,
        'provider',       'email'
      ),
      'email', now(), now(), now()
    where not exists (
      select 1 from auth.identities
      where user_id = v_user_id and provider = 'email'
    );
  end if;

  -- CrÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬ÃƒÂ¢Ã¢â‚¬Å¾Ã‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚Â ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¾Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¾ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬ÃƒÂ¢Ã¢â‚¬Å¾Ã‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¾ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬ÃƒÂ¢Ã¢â‚¬Å¾Ã‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚Â ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¾Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚Â¦ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬ÃƒÂ¢Ã¢â‚¬Å¾Ã‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â¦ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â©er le profil seulement s'il n'existe pas encore
  if not exists (select 1 from public.profiles where id = v_user_id) then
    insert into public.profiles (
      id, username, display_name, balance,
      role, is_banned, avatar_url, created_at
    )
    values (
      v_user_id,
      v_request.username,
      v_request.first_name || ' ' || v_request.last_name,
      p_initial_balance,
      'student', false, v_request.avatar_url, now()
    );
  end if;

  insert into public.transactions (
    from_user_id, to_user_id, amount, type, description, metadata
  )
  values (
    v_admin_id, v_user_id, p_initial_balance,
    'initial_balance', 'Solde initial',
    jsonb_build_object('account_request_id', p_request_id)
  );

  insert into public.notifications (user_id, type, title, body, data)
  values (
    v_user_id, 'account_approved',
    'Compte approuve',
    'Ton compte SES Coin a ete approuve.',
    jsonb_build_object('initial_balance', p_initial_balance)
  );

  update public.account_requests
  set status = 'approved', initial_balance = p_initial_balance,
      reviewed_at = now(), reviewed_by = v_admin_id
  where id = p_request_id;
end;
$$;


-- ============================================================
-- RPC : transfer_funds
-- ============================================================

create or replace function public.transfer_funds(
  p_from_user_id uuid,
  p_to_user_id uuid,
  p_amount numeric,
  p_description text,
  p_type text default 'transfer',
  p_metadata jsonb default '{}'::jsonb
)
returns jsonb
language plpgsql security definer set search_path = public
as $$
declare
  v_from public.profiles%rowtype;
  v_to public.profiles%rowtype;
  v_tx public.transactions%rowtype;
begin
  if p_amount <= 0 then
    raise exception 'Montant invalide.';
  end if;

  if p_from_user_id = p_to_user_id then
    raise exception 'Impossible de s''envoyer des fonds à soi-même.';
  end if;

  select * into v_from from public.profiles where id = p_from_user_id for update;
  if not found then raise exception 'Envoyeur introuvable.'; end if;

  select * into v_to from public.profiles where id = p_to_user_id for update;
  if not found then raise exception 'Destinataire introuvable.'; end if;

  if v_from.is_banned or v_to.is_banned then
    raise exception 'Un des comptes est banni.';
  end if;

  if v_from.role <> 'admin' and v_from.balance < p_amount then
    raise exception 'Solde insuffisant.';
  end if;

  if v_from.role <> 'admin' then
    update public.profiles set balance = balance - p_amount where id = p_from_user_id;
  end if;

  update public.profiles set balance = balance + p_amount where id = p_to_user_id;

  insert into public.transactions (
    from_user_id,
    to_user_id,
    amount,
    type,
    description,
    metadata
  )
  values (
    p_from_user_id,
    p_to_user_id,
    p_amount,
    coalesce(p_type, 'transfer'),
    p_description,
    coalesce(p_metadata, '{}'::jsonb)
  )
  returning * into v_tx;

  insert into public.notifications (user_id, type, title, body, data)
  values
    (p_to_user_id, 'transaction_received', 'Paiement reçu',
     'Tu as reçu ' || p_amount || ' SC.',
     jsonb_build_object('transaction_id', v_tx.id)),
    (p_from_user_id, 'transaction_sent', 'Paiement envoyé',
     'Tu as envoyé ' || p_amount || ' SC.',
     jsonb_build_object('transaction_id', v_tx.id));

  return to_jsonb(v_tx);
end;
$$;


-- ============================================================
-- RPC : paiement QR / NFC
-- ============================================================

create or replace function public.create_payment_request(
  p_recipient_id uuid,
  p_amount numeric,
  p_description text,
  p_payment_method text default null
)
returns uuid
language plpgsql security definer set search_path = public
as $$
declare
  v_token uuid;
begin
  if auth.uid() <> p_recipient_id then
    raise exception 'Non autorise.';
  end if;

  if p_amount <= 0 then
    raise exception 'Montant invalide.';
  end if;

  if p_payment_method is not null and p_payment_method not in ('qr', 'nfc') then
    raise exception 'Méthode de paiement invalide.';
  end if;

  insert into public.payment_requests (recipient_id, amount, description, payment_method)
  values (p_recipient_id, p_amount, p_description, p_payment_method)
  returning token into v_token;

  return v_token;
end;
$$;


create or replace function public.confirm_payment_request(
  p_payer_id uuid,
  p_payment_token uuid
)
returns jsonb
language plpgsql security definer set search_path = public
as $$
declare
  v_req public.payment_requests%rowtype;
  v_tx jsonb;
  v_tx_id uuid;
begin
  if auth.uid() <> p_payer_id then
    raise exception 'Non autorisé.';
  end if;

  select * into v_req
  from public.payment_requests
  where token = p_payment_token and status = 'pending'
  for update;

  if not found then
    raise exception 'Demande de paiement introuvable ou expirée.';
  end if;

  if v_req.expires_at < now() then
    update public.payment_requests set status = 'expired' where token = p_payment_token;
    raise exception 'Demande de paiement expirée.';
  end if;

  v_tx := public.transfer_funds(
    p_payer_id,
    v_req.recipient_id,
    v_req.amount,
    v_req.description,
    'transfer',
    jsonb_strip_nulls(jsonb_build_object('payment_method', v_req.payment_method))
  );
  v_tx_id := (v_tx ->> 'id')::uuid;

  update public.payment_requests
  set payer_id = p_payer_id, transaction_id = v_tx_id, status = 'confirmed'
  where token = p_payment_token;

  insert into public.notifications (user_id, type, title, body, data)
  values (
    v_req.recipient_id, 'transaction_confirmation_required',
    'Paiement à confirmer',
    'Un paiement de ' || v_req.amount || ' SC a été effectué. Confirme la réception.',
    jsonb_build_object('transaction_id', v_tx_id, 'payment_token', p_payment_token)
  );

  return v_tx;
end;
$$;


create or replace function public.acknowledge_payment(
  p_recipient_id uuid,
  p_transaction_id uuid
)
returns void
language plpgsql security definer set search_path = public
as $$
begin
  if auth.uid() <> p_recipient_id then
    raise exception 'Non autorise.';
  end if;

  update public.payment_requests
  set status = 'acknowledged'
  where recipient_id = p_recipient_id
    and transaction_id = p_transaction_id
    and status = 'confirmed';
end;
$$;


-- ============================================================
-- RPC : marketplace
-- ============================================================

create or replace function public.purchase_marketplace_item(
  p_buyer_id uuid,
  p_item_id uuid,
  p_quantity integer default 1
)
returns jsonb
language plpgsql security definer set search_path = public
as $$
declare
  v_item public.marketplace_items%rowtype;
  v_total numeric(12,2);
  v_admin_id uuid;
  v_tx jsonb;
  v_tx_id uuid;
  v_purchase_id uuid;
begin
  if auth.uid() <> p_buyer_id then
    raise exception 'Non autorise.';
  end if;

  if p_quantity < 1 then
    raise exception 'Quantite invalide.';
  end if;

  select * into v_item
  from public.marketplace_items
  where id = p_item_id and is_active = true
  for update;

  if not found then raise exception 'Item indisponible.'; end if;

  if v_item.stock <> -1 and v_item.stock < p_quantity then
    raise exception 'Stock insuffisant.';
  end if;

  select id into v_admin_id from public.profiles
  where role = 'admin' order by created_at asc limit 1;

  if v_admin_id is null then
    raise exception 'Aucun compte admin trouve.';
  end if;

  v_total := v_item.price * p_quantity;

  v_tx := public.transfer_funds(
    p_buyer_id, v_admin_id, v_total,
    'Achat marketplace : ' || v_item.name, 'purchase'
  );
  v_tx_id := (v_tx ->> 'id')::uuid;

  if v_item.stock <> -1 then
    update public.marketplace_items set stock = stock - p_quantity
    where id = p_item_id returning * into v_item;
  end if;

  insert into public.purchases (buyer_id, item_id, quantity, total_price, transaction_id)
  values (p_buyer_id, p_item_id, p_quantity, v_total, v_tx_id)
  returning id into v_purchase_id;

  insert into public.notifications (user_id, type, title, body, data)
  values (
    p_buyer_id, 'marketplace_purchase', 'Achat confirme',
    'Tu as achete : ' || v_item.name,
    jsonb_build_object('purchase_id', v_purchase_id, 'item_id', p_item_id)
  );

  return jsonb_build_object('purchase_id', v_purchase_id, 'transaction', v_tx, 'item', to_jsonb(v_item));
end;
$$;


