create or replace function public.place_auction_bid(
  p_bidder_id uuid,
  p_auction_id uuid,
  p_amount numeric
)
returns jsonb
language plpgsql security definer set search_path = public
as $$
declare
  v_auction public.auctions%rowtype;
  v_bidder public.profiles%rowtype;
  v_previous_winner uuid;
  v_previous_amount numeric(12,2);
begin
  if auth.uid() <> p_bidder_id then
    raise exception 'Non autorise.';
  end if;

  select * into v_auction from public.auctions where id = p_auction_id for update;
  if not found then raise exception 'Enchere introuvable.'; end if;

  if v_auction.status <> 'active' then
    raise exception 'Cette ench?re n''est pas active.';
  end if;

  if now() > v_auction.ends_at then
    raise exception 'Cette ench?re est termin?e.';
  end if;

  if p_amount <= v_auction.current_price then
    raise exception 'Le montant doit etre superieur a l''offre actuelle.';
  end if;

  select * into v_bidder from public.profiles where id = p_bidder_id for update;
  if not found or v_bidder.is_banned then
    raise exception 'Compte encherisseur invalide.';
  end if;

  if v_bidder.role <> 'admin' and v_bidder.balance < p_amount then
    raise exception 'Solde insuffisant.';
  end if;

  v_previous_winner := v_auction.current_winner_id;
  v_previous_amount := v_auction.current_price;

  if v_previous_winner is not null then
    update public.profiles set balance = balance + v_previous_amount
    where id = v_previous_winner;
  end if;

  if v_bidder.role <> 'admin' then
    update public.profiles set balance = balance - p_amount where id = p_bidder_id;
  end if;

  insert into public.auction_bids (auction_id, bidder_id, bidder_username, amount)
  values (p_auction_id, p_bidder_id, v_bidder.username, p_amount);

  update public.auctions
  set current_price = p_amount, current_winner_id = p_bidder_id,
      current_winner_username = v_bidder.username,
      current_winner_emoji = null,
      bid_count = bid_count + 1
  where id = p_auction_id
  returning * into v_auction;

  if v_previous_winner is not null then
    insert into public.notifications (user_id, type, title, body, data)
    values (
      v_previous_winner, 'auction_outbid', 'Tu as ?t? d?pass?',
      'Quelqu''un a surench?ri sur ' || v_auction.item_name,
      jsonb_build_object('auction_id', p_auction_id)
    );
  end if;

  return to_jsonb(v_auction);
end;
$$;


create or replace function public.cancel_auction(p_auction_id uuid)
returns void
language plpgsql security definer set search_path = public
as $$
declare
  v_auction public.auctions%rowtype;
begin
  if not public.current_profile_is_admin() then
    raise exception 'Action reservee a l''administrateur.';
  end if;

  select * into v_auction from public.auctions where id = p_auction_id for update;
  if not found then raise exception 'Enchere introuvable.'; end if;

  if v_auction.current_winner_id is not null then
    update public.profiles set balance = balance + v_auction.current_price
    where id = v_auction.current_winner_id;
  end if;

  update public.auctions set status = 'cancelled' where id = p_auction_id;
end;
$$;


create or replace function public.finalize_auction(p_auction_id uuid)
returns void
language plpgsql security definer set search_path = public
as $$
declare
  v_auction public.auctions%rowtype;
begin
  if not public.current_profile_is_admin() then
    raise exception 'Action reservee a l''administrateur.';
  end if;

  select * into v_auction from public.auctions where id = p_auction_id for update;
  if not found then raise exception 'Enchere introuvable.'; end if;

  update public.auctions set status = 'ended' where id = p_auction_id;

  if v_auction.current_winner_id is not null then
    insert into public.notifications (user_id, type, title, body, data)
    values (
      v_auction.current_winner_id, 'auction_won', 'Enchère gagnée',
      'Tu as gagné : ' || v_auction.item_name,
      jsonb_build_object('auction_id', p_auction_id)
    );
  end if;
end;
$$;


create or replace function public.finalize_expired_auctions()
returns integer
language plpgsql security definer set search_path = public
as $$
declare
  v_auction record;
  v_count integer := 0;
begin
  for v_auction in
    select *
    from public.auctions
    where status in ('active', 'upcoming')
      and ends_at <= now()
    for update
  loop
    update public.auctions
    set status = 'ended'
    where id = v_auction.id;

    if v_auction.current_winner_id is not null then
      insert into public.notifications (user_id, type, title, body, data)
      values (
        v_auction.current_winner_id, 'auction_won', 'Enchère gagnée',
        'Tu as gagné : ' || v_auction.item_name,
        jsonb_build_object('auction_id', v_auction.id)
      );
    end if;

    v_count := v_count + 1;
  end loop;

  return v_count;
end;
$$;


create or replace function public.set_auction_winner_emoji(
  p_auction_id uuid,
  p_emoji text
)
returns jsonb
language plpgsql security definer set search_path = public
as $$
declare
  v_auction public.auctions%rowtype;
begin
  select * into v_auction
  from public.auctions
  where id = p_auction_id
  for update;

  if not found then
    raise exception 'Enchere introuvable.';
  end if;

  if auth.uid() <> v_auction.current_winner_id then
    raise exception 'Seul le meilleur encherisseur peut choisir un emoji.';
  end if;

  update public.auctions
  set current_winner_emoji = nullif(trim(p_emoji), '')
  where id = p_auction_id
  returning * into v_auction;

  return to_jsonb(v_auction);
end;
$$;


