create or replace function public.request_loan(
  p_borrower_id uuid,
  p_lender_id uuid,
  p_principal numeric,
  p_interest_rate numeric,
  p_total_due numeric,
  p_due_date timestamptz,
  p_note text
)
returns jsonb
language plpgsql security definer set search_path = public
as $$
declare
  v_borrower public.profiles%rowtype;
  v_lender public.profiles%rowtype;
  v_loan public.loans%rowtype;
begin
  if auth.uid() <> p_borrower_id then raise exception 'Non autorise.'; end if;
  if p_borrower_id = p_lender_id then raise exception 'Impossible de se pr?ter ? soi-m?me.'; end if;

  select * into v_borrower from public.profiles where id = p_borrower_id;
  select * into v_lender from public.profiles where id = p_lender_id;

  if v_borrower.id is null or v_lender.id is null then
    raise exception 'Compte introuvable.';
  end if;
  if v_lender.role = 'admin' then
    raise exception 'Impossible de demander un pr?t ? un administrateur.';
  end if;

  insert into public.loans (
    lender_id, lender_username, borrower_id, borrower_username,
    principal, interest_rate, total_due, amount_repaid,
    status, due_date, note
  )
  values (
    p_lender_id, v_lender.username, p_borrower_id, v_borrower.username,
    p_principal, p_interest_rate, p_total_due, 0,
    'pending', p_due_date, p_note
  )
  returning * into v_loan;

  insert into public.notifications (user_id, type, title, body, data)
  values (
    p_lender_id, 'loan_requested', 'Demande de prêt',
    v_borrower.username || ' te demande un prêt de ' || p_principal || ' SC.',
    jsonb_build_object('loan_id', v_loan.id)
  );

  return to_jsonb(v_loan);
end;
$$;


create or replace function public.accept_loan(p_loan_id uuid, p_lender_id uuid)
returns jsonb
language plpgsql security definer set search_path = public
as $$
declare
  v_loan public.loans%rowtype;
  v_lender public.profiles%rowtype;
begin
  if auth.uid() <> p_lender_id then raise exception 'Non autorise.'; end if;

  select * into v_loan
  from public.loans
  where id = p_loan_id and lender_id = p_lender_id and status = 'pending'
  for update;
  if not found then raise exception 'Prêt introuvable.'; end if;

  select * into v_lender from public.profiles where id = p_lender_id for update;

  if v_lender.role <> 'admin' and v_lender.balance < v_loan.principal then
    raise exception 'Solde insuffisant.';
  end if;

  if v_lender.role <> 'admin' then
    update public.profiles set balance = balance - v_loan.principal where id = p_lender_id;
  end if;

  update public.profiles set balance = balance + v_loan.principal where id = v_loan.borrower_id;
  update public.loans set status = 'active' where id = p_loan_id returning * into v_loan;

  insert into public.transactions (from_user_id, to_user_id, amount, type, description, metadata)
  values (
    p_lender_id, v_loan.borrower_id, v_loan.principal,
    'loan', 'Prêt accordé', jsonb_build_object('loan_id', v_loan.id)
  );

  insert into public.notifications (user_id, type, title, body, data)
  values (
    v_loan.borrower_id, 'loan_accepted', 'Prêt accepté',
    'Ton prêt de ' || v_loan.principal || ' SC a été accepté.',
    jsonb_build_object('loan_id', v_loan.id)
  );

  return to_jsonb(v_loan);
end;
$$;


create or replace function public.repay_loan(
  p_loan_id uuid,
  p_borrower_id uuid,
  p_amount numeric
)
returns jsonb
language plpgsql security definer set search_path = public
as $$
declare
  v_loan public.loans%rowtype;
  v_borrower public.profiles%rowtype;
  v_amount numeric(12,2);
begin
  if auth.uid() <> p_borrower_id then raise exception 'Non autorise.'; end if;
  if p_amount <= 0 then raise exception 'Montant invalide.'; end if;

  select * into v_loan
  from public.loans
  where id = p_loan_id and borrower_id = p_borrower_id and status = 'active'
  for update;
  if not found then raise exception 'Prêt introuvable.'; end if;

  v_amount := least(p_amount, v_loan.total_due - v_loan.amount_repaid);

  select * into v_borrower from public.profiles where id = p_borrower_id for update;
  if v_borrower.balance < v_amount then raise exception 'Solde insuffisant.'; end if;

  update public.profiles set balance = balance - v_amount where id = p_borrower_id;
  update public.profiles set balance = balance + v_amount where id = v_loan.lender_id;

  update public.loans
  set amount_repaid = amount_repaid + v_amount,
      status = case when amount_repaid + v_amount >= total_due then 'repaid' else 'active' end
  where id = p_loan_id
  returning * into v_loan;

  insert into public.transactions (from_user_id, to_user_id, amount, type, description, metadata)
  values (
    p_borrower_id, v_loan.lender_id, v_amount,
    'loan', 'Remboursement de prêt', jsonb_build_object('loan_id', v_loan.id)
  );

  insert into public.notifications (user_id, type, title, body, data)
  values (
    v_loan.lender_id, 'loan_repaid', 'Remboursement reçu',
    'Tu as reçu un remboursement de ' || v_amount || ' SC.',
    jsonb_build_object('loan_id', v_loan.id)
  );

  return to_jsonb(v_loan);
end;
$$;


-- ============================================================
-- RPC : admin
-- ============================================================

create or replace function public.admin_adjust_balance(
  p_user_id uuid,
  p_amount numeric,
  p_reason text
)
returns void
language plpgsql security definer set search_path = public
as $$
declare
  v_admin_id uuid;
  v_type text;
begin
  if not public.current_profile_is_admin() then
    raise exception 'Action reservee a l''administrateur.';
  end if;

  v_admin_id := auth.uid();

  update public.profiles set balance = greatest(0, balance + p_amount) where id = p_user_id;

  v_type := case when p_amount >= 0 then 'admin_credit' else 'admin_debit' end;

  insert into public.transactions (from_user_id, to_user_id, amount, type, description)
  values (
    case when p_amount >= 0 then v_admin_id else p_user_id end,
    case when p_amount >= 0 then p_user_id else v_admin_id end,
    abs(p_amount), v_type, p_reason
  );
end;
$$;


create or replace function public.admin_tax_all(p_percent numeric, p_reason text)
returns void
language plpgsql security definer set search_path = public
as $$
declare
  v_admin_id uuid;
  v_user record;
  v_amount numeric(12,2);
begin
  if not public.current_profile_is_admin() then
    raise exception 'Action reservee a l''administrateur.';
  end if;

  if p_percent <= 0 or p_percent > 100 then
    raise exception 'Pourcentage invalide.';
  end if;

  v_admin_id := auth.uid();

  for v_user in
    select * from public.profiles
    where role <> 'admin' and is_banned = false and balance > 0
    for update
  loop
    v_amount := round(v_user.balance * p_percent / 100, 2);

    update public.profiles set balance = balance - v_amount where id = v_user.id;

    insert into public.transactions (from_user_id, to_user_id, amount, type, description)
    values (v_user.id, v_admin_id, v_amount, 'tax', p_reason);

    insert into public.notifications (user_id, type, title, body, data)
    values (
      v_user.id, 'admin_tax', 'Taxe appliquée',
      'Une taxe de ' || p_percent || '% a été appliquée.',
      jsonb_build_object('amount', v_amount, 'reason', p_reason)
    );
  end loop;
end;
$$;


create or replace function public.admin_reward_all(p_amount numeric, p_reason text)
returns void
language plpgsql security definer set search_path = public
as $$
declare
  v_admin_id uuid;
  v_user record;
begin
  if not public.current_profile_is_admin() then
    raise exception 'Action reservee a l''administrateur.';
  end if;

  if p_amount <= 0 then raise exception 'Montant invalide.'; end if;

  v_admin_id := auth.uid();

  for v_user in
    select * from public.profiles where role <> 'admin' and is_banned = false
  loop
    update public.profiles set balance = balance + p_amount where id = v_user.id;

    insert into public.transactions (from_user_id, to_user_id, amount, type, description)
    values (v_admin_id, v_user.id, p_amount, 'reward', p_reason);

    insert into public.notifications (user_id, type, title, body, data)
    values (
      v_user.id, 'admin_reward', 'Récompense reçue',
      'Tu as reçu ' || p_amount || ' SC.',
      jsonb_build_object('amount', p_amount, 'reason', p_reason)
    );
  end loop;
end;
$$;


create or replace function public.admin_delete_user(p_user_id uuid)
returns void
language plpgsql security definer set search_path = public, auth
as $$
begin
  if not public.current_profile_is_admin() then
    raise exception 'Action reservee a l''administrateur.';
  end if;

  delete from auth.users where id = p_user_id;
end;
$$;


-- ============================================================
-- RPC : calculate_currency_rate
-- ============================================================

create or replace function public.calculate_currency_rate()
returns jsonb
language plpgsql security definer set search_path = public
as $$
declare
  v_count integer;
  v_previous public.exchange_rates%rowtype;
  v_new_rate numeric(10,4);
  v_change numeric(8,4);
  v_rate public.exchange_rates%rowtype;
begin
  select count(*) into v_count
  from public.transactions
  where created_at >= now() - interval '24 hours';

  select * into v_previous from public.exchange_rates order by created_at desc limit 1;

  if v_previous.id is null then
    v_new_rate := 1.0000;
    v_change := 0;
  else
    v_new_rate := v_previous.rate * (1 + (v_count / 1000.0));
    v_new_rate := greatest(0.5, least(5.0, v_new_rate));
    v_change := ((v_new_rate - v_previous.rate) / v_previous.rate) * 100;
  end if;

  insert into public.exchange_rates (
    rate, change_percent, reason, is_manual,
    demand_points, supply_points, price_points
  )
  values (
    v_new_rate, v_change,
    'Calcul automatique base sur l''activite',
    false,
    coalesce(v_previous.demand_points, '[0,189,180,147,705,0,0,0,0,0]'::jsonb),
    coalesce(v_previous.supply_points, '[0,161,29,138,139,0,0,0,0,0]'::jsonb),
    coalesce(v_previous.price_points, '[1.0,1.1,7.2,7.7,39.3,39.3,39.3,39.3,39.3,39.3]'::jsonb)
  )
  returning * into v_rate;

  return to_jsonb(v_rate);
end;
$$;


-- ============================================================
-- RPC : broadcast_notification
-- ============================================================

create or replace function public.broadcast_notification(
  p_type text,
  p_title text,
  p_body text,
  p_data jsonb default null
)
returns void
language plpgsql security definer set search_path = public
as $$
begin
  if not public.current_profile_is_admin() then
    raise exception 'Action reservee a l''administrateur.';
  end if;

  insert into public.notifications (user_id, type, title, body, data)
  select id, p_type, p_title, p_body, p_data
  from public.profiles
  where is_banned = false;
end;
$$;


-- ============================================================
-- RLS
-- ============================================================

alter table public.profiles enable row level security;
alter table public.account_requests enable row level security;
alter table public.transactions enable row level security;
alter table public.marketplace_items enable row level security;
alter table public.purchases enable row level security;
alter table public.auctions enable row level security;
alter table public.auction_bids enable row level security;
alter table public.loans enable row level security;
alter table public.exchange_rates enable row level security;
alter table public.notifications enable row level security;
alter table public.payment_requests enable row level security;

-- profiles
create policy "profiles_select_all" on public.profiles for select using (true);
create policy "profiles_update_own" on public.profiles for update
  using (auth.uid() = id) with check (auth.uid() = id);

-- account_requests (lecture + modification admin, insert via RPC security definer)
create policy "account_requests_select_admin" on public.account_requests
  for select using (public.current_profile_is_admin());
create policy "account_requests_update_admin" on public.account_requests
  for update using (public.current_profile_is_admin());

-- transactions
create policy "transactions_select_own_or_admin" on public.transactions
  for select using (
    auth.uid() = from_user_id or auth.uid() = to_user_id
    or public.current_profile_is_admin()
  );

-- marketplace_items
create policy "marketplace_items_select_all" on public.marketplace_items
  for select using (true);
create policy "marketplace_items_admin_insert" on public.marketplace_items
  for insert with check (public.current_profile_is_admin());
create policy "marketplace_items_admin_update" on public.marketplace_items
  for update using (public.current_profile_is_admin())
  with check (public.current_profile_is_admin());
create policy "marketplace_items_admin_delete" on public.marketplace_items
  for delete using (public.current_profile_is_admin());

-- purchases
create policy "purchases_select_own_or_admin" on public.purchases
  for select using (auth.uid() = buyer_id or public.current_profile_is_admin());

-- auctions
create policy "auctions_select_all" on public.auctions for select using (true);
create policy "auctions_admin_insert" on public.auctions
  for insert with check (public.current_profile_is_admin());
create policy "auctions_admin_update" on public.auctions
  for update using (public.current_profile_is_admin())
  with check (public.current_profile_is_admin());
create policy "auctions_admin_delete" on public.auctions
  for delete using (public.current_profile_is_admin());

-- auction_bids
create policy "auction_bids_select_all" on public.auction_bids for select using (true);

-- loans
create policy "loans_select_own_or_admin" on public.loans
  for select using (
    auth.uid() = lender_id or auth.uid() = borrower_id
    or public.current_profile_is_admin()
  );

-- exchange_rates
create policy "exchange_rates_select_all" on public.exchange_rates for select using (true);
create policy "exchange_rates_admin_insert" on public.exchange_rates
  for insert to authenticated
  with check (public.current_profile_is_admin());

-- notifications
create policy "notifications_select_own" on public.notifications
  for select using (auth.uid() = user_id);
create policy "notifications_update_own" on public.notifications
  for update using (auth.uid() = user_id) with check (auth.uid() = user_id);
create policy "notifications_delete_own" on public.notifications
  for delete using (auth.uid() = user_id);

-- payment_requests
create policy "payment_requests_select_own" on public.payment_requests
  for select using (auth.uid() = recipient_id or auth.uid() = payer_id);


