grant execute on function public.submit_account_request to anon, authenticated;
grant execute on function public.is_username_available to anon, authenticated;
grant execute on function public.approve_account_request to authenticated;
grant execute on function public.transfer_funds to authenticated;
grant execute on function public.create_payment_request to authenticated;
grant execute on function public.confirm_payment_request to authenticated;
grant execute on function public.acknowledge_payment to authenticated;
grant execute on function public.purchase_marketplace_item to authenticated;
grant execute on function public.place_auction_bid to authenticated;
grant execute on function public.cancel_auction to authenticated;
grant execute on function public.finalize_auction to authenticated;
grant execute on function public.request_loan to authenticated;
grant execute on function public.accept_loan to authenticated;
grant execute on function public.repay_loan to authenticated;
grant execute on function public.admin_adjust_balance to authenticated;
grant execute on function public.admin_tax_all to authenticated;
grant execute on function public.admin_reward_all to authenticated;
grant execute on function public.admin_delete_user to authenticated;
grant execute on function public.calculate_currency_rate to authenticated;
grant execute on function public.broadcast_notification to authenticated;
grant execute on function public.approve_avatar_change to authenticated;
grant execute on function public.reject_avatar_change to authenticated;
grant execute on function public.finalize_expired_auctions to authenticated;
grant execute on function public.set_auction_winner_emoji to authenticated;


-- ============================================================
-- STORAGE : bucket avatars public
-- ============================================================

insert into storage.buckets (id, name, public, file_size_limit, allowed_mime_types)
values (
  'avatars', 'avatars', true, 5242880,
  array['image/jpeg', 'image/png', 'image/webp', 'image/gif']
)
on conflict (id) do update set public = true;

create policy "avatars_public_read" on storage.objects
  for select using (bucket_id = 'avatars');

create policy "avatars_auth_write" on storage.objects
  for insert to authenticated
  with check (bucket_id = 'avatars');

create policy "avatars_anon_request_write" on storage.objects
  for insert to anon
  with check (
    bucket_id = 'avatars'
    and (storage.foldername(name))[1] = 'requests'
  );

create policy "avatars_auth_update" on storage.objects
  for update to authenticated
  using (bucket_id = 'avatars');

create policy "avatars_auth_delete" on storage.objects
  for delete to authenticated
  using (bucket_id = 'avatars');


do $$
declare
  v_admin_id   uuid;
  v_admin_email text := 'admin@sescoin.local';
  v_admin_pass  text := 'profses';
